import { useEffect, useState } from "react";
import axios from "axios";

function Leads() {
    const [leads, setLeads] = useState([]);

    useEffect(() => {
        fetch("http://localhost:8000/leads") // your FastAPI URL
            .then((res) => res.json())
            .then((data) => {
                console.log("API Response:", data);
                setLeads(data.leads); // store leads array
            })
            .catch((err) => console.error("Error fetching leads:", err));
    }, []);

    return (
        <div>
            <h2>Leads Data</h2>
            <table border="1" cellPadding="8" style={{ borderCollapse: "collapse" }}>
                <thead>
                    <tr>
                        <th>ID</th>
                        <th>Campaign</th>
                        <th>Date</th>
                        <th>First Name</th>
                        <th>Last Name</th>
                        <th>Email</th>
                        <th>Phone</th>
                        <th>Company</th>
                        <th>Domain</th>
                        <th>Followed By</th>
                        <th>Uploaded By</th>
                        <th>Uploaded Date</th>
                    </tr>
                </thead>
                <tbody>
                    {leads.map((lead, index) => (
                        <tr key={index}>
                            <td>{lead.id}</td>
                            <td>{lead.campaign}</td>
                            <td>{lead.date}</td>
                            <td>{lead.first_name}</td>
                            <td>{lead.last_name}</td>
                            <td>{lead.email_address}</td>
                            <td>{lead.phone}</td>
                            <td>{lead.company}</td>
                            <td>{lead.domain}</td>
                            <td>{lead.followed_by}</td>
                            <td>{lead.uploaded_by}</td>
                            <td>{lead.uploaded_dt}</td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
}

export default Leads;
